import java.util.*;class Player{static int n,r=9999;static int[][]O;static List<String>S=new ArrayList<>();static void f(int m,int l,int c){if(m==(1<<n)-1){r=Math.min(r,c);return;}for(int j=0;j<n;j++)if((m>>j&1)==0)f(m|1<<j,j,c+S.get(j).length()-O[l][j]);}public static void main(String[]a){var s=new Scanner(System.in);int N=s.nextInt();var T=new String[N];for(int i=0;i<N;i++)T[i]=s.next();for(var x:T){boolean sub=false;for(var t:T)if(!x.equals(t)&&t.contains(x))sub=true;if(!sub)S.add(x);}n=S.size();if(n<2){System.out.println(n>0?S.get(0).length():0);return;}O=new int[n][n];for(int i=0;i<n;i++)for(int j=0;j<n;j++)if(i!=j)for(int k=1;k<=Math.min(S.get(i).length(),S.get(j).length());k++)if(S.get(i).endsWith(S.get(j).substring(0,k)))O[i][j]=k;for(int i=0;i<n;i++)f(1<<i,i,S.get(i).length());System.out.println(r);}}